import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Encode user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        String output = "<p>Welcome, " + encodedUserInput + "</p>";

        try {
            File file = new File("output.html");
            FileWriter writer = new FileWriter(file);
            writer.write(output);
            writer.close();
            System.out.println("Output has been written to output.html");
        } catch (IOException e) {
            System.out.println("An error occurred while writing the output.");
            e.printStackTrace();
        }
    }
}

